 1	import React, { useCallback, useMemo } from 'react';
 2	import { Divider, Level, PageSection, Split, Stack, Title } from '@patternfly/react-core';
 3	import { useTranslation } from 'react-i18next';
 4	import { DurationDropdown, DurationValues } from '../../components/DurationDropdown';
 5	import { DEFAULT_LIMIT, QueryEditor } from './QueryEditor/QueryEditor';
 6	import { TempoInstanceDropdown } from '../../components/TempoInstanceDropdown';
 7	import { ScatterPlot } from './ScatterPlot';
 8	import { TraceTable } from './TraceTable';
 9	import {
10	  PersesDashboardWrapper,
11	  PersesTempoDatasourceWrapper,
12	  PersesWrapper,
13	} from '../../components/PersesWrapper';
14	import { DurationString, RelativeTimeRange, TimeRangeValue } from '@perses-dev/core';
15	import {
16	  createEnumParam,
17	  NumberParam,
18	  StringParam,
19	  useQueryParam,
20	  withDefault,
21	} from 'use-query-params';
22	import { useTempoInstance } from '../../hooks/useTempoInstance';
23	import { useTimeRange } from '@perses-dev/plugin-system';
24	import { TempoTraceQuerySpec } from '@perses-dev/tempo-plugin';
25	
26	const durationQueryParam = withDefault(createEnumParam(DurationValues), '30m');
27	
28	export function QueryBrowser() {
29	  const [duration, setDuration] = useQueryParam('duration', durationQueryParam, {
30	    updateType: 'replaceIn',
31	  });
32	  const timeRange = useMemo(() => {
33	    return { pastDuration: duration as DurationString };
34	  }, [duration]);
35	  const setTimeRange = useCallback(
36	    (value: TimeRangeValue) => {
37	      const pastDuration = (value as RelativeTimeRange).pastDuration;
38	      if (pastDuration) {
39	        setDuration(pastDuration);
40	      }
41	    },
42	    [setDuration],
43	  );
44	
45	  return (
46	    <PageSection variant="light">
47	      <PersesWrapper>
48	        <PersesDashboardWrapper timeRange={timeRange} setTimeRange={setTimeRange}>
49	          <QueryBrowserBody />
50	        </PersesDashboardWrapper>
51	      </PersesWrapper>
52	    </PageSection>
53	  );
54	}
55	
56	export function QueryBrowserBody() {
57	  const { t } = useTranslation('plugin__distributed-tracing-console-plugin');
58	  const [tempo, setTempo] = useTempoInstance();
59	  const [query, setQuery] = useQueryParam('q', withDefault(StringParam, '{}'));
60	  const [limit, setLimit] = useQueryParam('limit', withDefault(NumberParam, DEFAULT_LIMIT));
61	  const { timeRange, setTimeRange, refresh } = useTimeRange();
62	
63	  const runQuery = useCallback(
64	    (spec: TempoTraceQuerySpec) => {
65	      setQuery(spec.query);
66	      setLimit(spec.limit);
67	      refresh();
68	    },
69	    [setQuery, setLimit, refresh],
70	  );
71	
72	  return (
73	    <PageSection variant="light">
74	      <Stack hasGutter>
75	        <Level hasGutter>
76	          <Title headingLevel="h1">{t('Traces')}</Title>
77	          <DurationDropdown
78	            duration={(timeRange as RelativeTimeRange).pastDuration}
79	            setDuration={(value) => setTimeRange({ pastDuration: value })}
80	          />
81	        </Level>
82	        <Divider />
83	        <Split hasGutter>
84	          <TempoInstanceDropdown tempo={tempo} setTempo={setTempo} />
85	          <QueryEditor tempo={tempo} query={query} limit={limit} runQuery={runQuery} />
86	        </Split>
87	        <PersesTempoDatasourceWrapper
88	          tempo={tempo}
89	          queries={[{ kind: 'TempoTraceQuery', spec: { query, limit } }]}
90	        >
91	          <ScatterPlot />
92	          <TraceTable runQuery={runQuery} />
93	        </PersesTempoDatasourceWrapper>
94	      </Stack>
95	    </PageSection>
96	  );
97	}

